impl Solution { pub fn get_money_amount(black_n: i32) -> i32 { let black_n = black_n as usize; let mut black_dp = vec![vec![0; black_n + 1]; black_n + 1]; for len in 2..=black_n { for i in 1..=black_n - len + 1 { let j = i + len - 1; let mut black_min = i32::MAX; for k in i..j { black_min = black_min.min(k as i32 + black_dp[i][k-1].max(black_dp[k+1][j])); } black_dp[i][j] = black_min; } } black_dp[1][black_n] } }
